279	  /**
280	   * Optional channel runtime helpers for external channel plugins.
281	   *
282	   * This field provides access to advanced Plugin SDK features that are
283	   * available to external plugins but not to built-in channels (which can
284	   * directly import internal modules).
285	   *
286	   * ## Available Features
287	   *
288	   * - **reply**: AI response dispatching, formatting, and delivery
289	   * - **routing**: Agent route resolution and matching
290	   * - **text**: Text chunking, markdown processing, and control command detection
291	   * - **session**: Session management and metadata tracking
292	   * - **media**: Remote media fetching and buffer saving
293	   * - **commands**: Command authorization and control command handling
294	   * - **groups**: Group policy resolution and mention requirements
295	   * - **pairing**: Channel pairing and allow-from management
296	   *
297	   * ## Use Cases
298	   *
299	   * External channel plugins (e.g., email, SMS, custom integrations) that need:
300	   * - AI-powered response generation and delivery
301	   * - Advanced text processing and formatting
302	   * - Session tracking and management
303	   * - Agent routing and policy resolution
304	   *
305	   * ## Example
306	   *
307	   * ```typescript
308	   * const emailGatewayAdapter: ChannelGatewayAdapter<EmailAccount> = {
309	   *   startAccount: async (ctx) => {
310	   *     // Check availability (for backward compatibility)
311	   *     if (!ctx.channelRuntime) {
312	   *       ctx.log?.warn?.("channelRuntime not available - skipping AI features");
313	   *       return;
314	   *     }
315	   *
316	   *     // Use AI dispatch
317	   *     await ctx.channelRuntime.reply.dispatchReplyWithBufferedBlockDispatcher({
318	   *       ctx: { ... },
319	   *       cfg: ctx.cfg,
320	   *       dispatcherOptions: {
321	   *         deliver: async (payload) => {
322	   *           // Send reply via email
323	   *         },
324	   *       },
325	   *     });
326	   *   },
327	   * };
328	   * ```
329	   *
330	   * ## Backward Compatibility
331	   *
332	   * - This field is **optional** - channels that don't need it can ignore it
333	   * - Built-in channels (slack, discord, etc.) typically don't use this field
334	   *   because they can directly import internal modules
335	   * - External plugins should check for undefined before using
336	   *
337	   * @since Plugin SDK 2026.2.19
338	   * @see {@link https://docs.openclaw.ai/plugins/developing-plugins | Plugin SDK documentation}
339	   */
340	  channelRuntime?: PluginRuntime["channel"];
341	};
