      ...createScopedChannelConfigAdapter({ /* ... */ }),
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: { host: account.host, port: account.port },
        }),
    },

    // Group/channel handling
    groups: {
      resolveRequireMention: ({ cfg, accountId, groupId }) => {
        // Return true if mentions required for this group
      },
      resolveToolPolicy: ({ cfg, accountId, groupId }) => {
        // Return tool policy for this group
      },
    },

    // Message routing
    messaging: {
      normalizeTarget: normalize[Channel]MessagingTarget,
      targetResolver: {
        looksLikeId: looksLike[Channel]TargetId,
        hint: "<#channel|nick>",
      },
    },

    // Directory (peers & groups listing)
    directory: createChannelDirectoryAdapter({
      listPeers: async (params) => list[Channel]DirectoryPeersFromConfig(params),
      listGroups: async (params) => list[Channel]DirectoryGroupsFromConfig(params),
    }),

    // Status reporting
    status: createComputedAccountStatusAdapter({
      defaultRuntime: createDefaultChannelRuntimeState("[channel-id]"),
      buildChannelSummary: ({ account, snapshot }) => ({
        ...buildBaseChannelStatusSummary(snapshot),
        host: account.host,
        probe: snapshot.probe,
      }),
      probeAccount: async ({ cfg, account, timeoutMs }) =>
        probe[Channel](cfg, { accountId: account.accountId, timeoutMs }),
    }),

    // Connection management
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        if (!account.configured) {
          throw new Error(`[Channel] not configured.`);
        }
        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () =>
            await monitor[Channel]Provider({
              accountId: account.accountId,
              config: ctx.cfg as CoreConfig,
              runtime: ctx.runtime,
              abortSignal: ctx.abortSignal,
            }),
        });
      },
    },
  },

  // DM pairing & approval
  pairing: {
    text: {
      idLabel: "[Channel] user",
      message: PAIRING_APPROVED_MESSAGE,
      normalizeAllowEntry: (entry) => normalize[Channel]AllowEntry(entry),
      notify: async ({ id, message }) => {
        await sendMessage[Channel](id, message);
      },
    },
  },

  // Security policies
  security: {
    resolveDmPolicy: resolve[Channel]DmPolicy,
    collectWarnings: collect[Channel]SecurityWarnings,
  },

  // Outbound message sending
  outbound: {
    base: {
      deliveryMode: "direct",
      chunker: chunkTextForOutbound,
      chunkerMode: "markdown",
      textChunkLimit: 350,
    },
    attachedResults: {
      channel: "[channel-id]",
      sendText: async ({ cfg, to, text, accountId, replyToId }) =>
        await sendMessage[Channel](to, text, {
          cfg: cfg as CoreConfig,
          accountId,
          replyTo: replyToId,
        }),
      sendMedia: async ({ cfg, to, text, mediaUrl, accountId }) =>
        await sendMessage[Channel](to, `${text}\n\nAttachment: ${mediaUrl}`, {
          cfg: cfg as CoreConfig,
          accountId,
        }),
    },
  },
});
```

**Key builder options:**
- `base` - Account setup, config, groups, messaging, directory, status, gateway
- `pairing` - DM approval workflow
- `security` - DM policy & security warnings
- `outbound` - Message sending with chunking & media
- `approval` - (Advanced) Native approval delivery for chat platforms

#### **12. `src/inbound.ts`** (if platform receives messages)

Handle inbound messages from the platform:

```typescript
export async function handleInboundMessages(params: {
  payload: InboundPayload;
  target: string;
  accountId: string;
  runtime: PluginRuntime;
  cfg: CoreConfig;
}) {
  const account = resolve[Channel]Account({ cfg: params.cfg, accountId: params.accountId });

  // Check DM security policy
  const access = await resolveInboundDirectDmAccessWithRuntime({
    cfg: params.cfg,
    channel: "[channel-id]",
    accountId: params.accountId,
    dmPolicy: account.dmPolicy,
    allowFrom: account.allowFrom,
    senderId: params.payload.senderId,
    isSenderAllowed: is[Channel]SenderAllowed,
    runtime: params.runtime,
  });

  if (access.disposition === "reject") {
    logInboundDrop("[channel-id]", "security", { reason: access.reason });
    return;
  }

  // Dispatch to core message handler
  await dispatchInboundReplyWithBase({
    channel: "[channel-id]",
    accountId: params.accountId,
    messageId: params.payload.id,
    target: params.target,
    text: params.payload.text,
    payload: access.payload,
    runtime: params.runtime,
  });
}
```

#### **13. `src/send.ts`**

Send messages to the platform:

```typescript
export async function sendMessage[Channel](
  to: string,
  text: string,
  opts: SendOptions = {},
): Promise<SendResult> {
  const runtime = get[Channel]Runtime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolve[Channel]Account({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(`[Channel] not configured for account "${account.accountId}".`);
  }

  const target = normalizeTarget(to);
  const prepared = convertMarkdownTables(text.trim(), tableMode);

  // Send via platform API (use client or direct connection)
  const result = await [channel]Client.send({
    target,
    text: prepared,
    accountId: account.accountId,
  });

  recordOutboundActivity(account.accountId);

  return { messageId: result.id, target };
}
```

