### **Test Structure**

Colocated test pattern (`.test.ts` files next to implementation):

```typescript
// src/channel.test.ts
import { describe, it, expect } from "vitest";
import { [channel]Plugin } from "./channel.js";

describe("[Channel] plugin", () => {
  it("resolves account from config", () => {
    const cfg = {
      channels: {
        "[channel-id]": { host: "example.com", nick: "bot" },
      },
    } as any;
    const account = [channel]Plugin.config!.resolveAccount?.(cfg, undefined);
    expect(account.configured).toBe(true);
  });

  it("validates required fields in setup", () => {
    const cfg = { channels: {} } as any;
    const result = [channel]SetupAdapter.validateInput?.({ input: {} });
    expect(result?.error).toBeDefined();
  });
});
```

