- **Additional**: `test-support/` directory

---

## 2. KEY FILES ANALYSIS

### openclaw.plugin.json (Plugin Manifest)

**Universal structure** - all plugins follow this pattern:

```json
{
  "id": "irc",                    // Unique channel identifier
  "channels": ["irc"],            // Supported channel types
  "configSchema": {               // JSON Schema (empty at root)
    "type": "object",
    "additionalProperties": false,
    "properties": {}
  }
}
```

### package.json Structure

All plugins follow this pattern:

**Standard fields**:
```json
{
  "name": "@openclaw/[channel-name]",
  "version": "2026.4.1-beta.1",
  "description": "OpenClaw [Channel] channel plugin",
  "type": "module",
  "dependencies": {  // Channel-specific dependencies
    "channel-specific-lib": "^version"
  },
  "devDependencies": {
    "openclaw": "workspace:*"
  },
  "peerDependencies": {
    "openclaw": ">=2026.4.1-beta.1"
  },
  "peerDependenciesMeta": {
    "openclaw": {
      "optional": true
    }
  },
  "openclaw": {  // Plugin-specific configuration
    "extensions": ["./index.ts"],
    "setupEntry": "./setup-entry.ts",
    "channel": {
      "id": "irc",
      "label": "IRC",
      "selectionLabel": "IRC (Server + Nick)",
      "docsPath": "/channels/irc",
      "docsLabel": "irc",
      "blurb": "classic IRC networks...",
      "aliases": ["internet-relay-chat"],
      "systemImage": "network"
    },
    "install": {
      "minHostVersion": ">=2026.4.1"
    }
  }
}
```

**Plugin-specific dependencies**:
- **IRC**: None (core Node.js based)
- **Nostr**: `nostr-tools: ^2.23.3`
- **Matrix**: `matrix-js-sdk: 41.3.0-rc.0`, `@matrix-org/matrix-sdk-crypto-*`, `fake-indexeddb`, `markdown-it`, `music-metadata`
- **Discord**: `@buape/carbon`, `@discordjs/voice`, `discord-api-types`, `opusscript`, `https-proxy-agent`
- **Zalo**: `undici: 7.24.6`

---

## 3. INDEX.TS ENTRY POINT PATTERNS

All plugins use `defineChannelPluginEntry()` with this pattern:

### Minimal Pattern (IRC, Nostr, Zalo):
```typescript
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { [channelName]Plugin } from "./src/channel.js";
import { set[ChannelName]Runtime } from "./src/runtime.js";

export { [channelName]Plugin } from "./src/channel.js";
export { set[ChannelName]Runtime } from "./src/runtime.js";

export default defineChannelPluginEntry({
  id: "[channel-id]",
  name: "[Channel Name]",
  description: "[Channel] channel plugin",
  plugin: [channelName]Plugin,
  setRuntime: set[ChannelName]Runtime,
});
```

### Extended Pattern (Matrix with CLI/Crypto):
```typescript
export default defineChannelPluginEntry({
  id: "matrix",
  name: "Matrix",
  description: "Matrix channel plugin",
  plugin: matrixPlugin,
  setRuntime: setMatrixRuntime,
  registerCliMetadata(api) {
    // Register CLI commands
  },
  registerFull(api) {
    // Register gateway methods
    api.registerGatewayMethod("matrix.verify.*", ...);
  },
});
```

### Advanced Pattern (Discord with Subagent Hooks):
```typescript
export default defineChannelPluginEntry({
  id: "discord",
  name: "Discord",
  description: "Discord channel plugin",
  plugin: discordPlugin,
  setRuntime: setDiscordRuntime,
  registerFull: registerDiscordSubagentHooks,
});
```

### Advanced Pattern (Nostr with HTTP Handler):
```typescript
export default defineChannelPluginEntry({
  id: "nostr",
  name: "Nostr",
  description: "Nostr DM channel plugin via NIP-04",
  plugin: nostrPlugin,
  setRuntime: setNostrRuntime,
  registerFull(api) {
    const httpHandler = createNostrProfileHttpHandler({
      getConfigProfile: (accountId: string) => { ... },
      updateConfigProfile: async (accountId: string, profile) => { ... },
      getAccountInfo: (accountId: string) => { ... },
    });
    api.registerHttpRoute({
      path: "/api/channels/nostr",
      auth: "gateway",
      match: "prefix",
      handler: httpHandler,
    });
  },
});
```

---

## 4. SETUP-ENTRY.TS PATTERN

All plugins use the same minimal pattern:

```typescript
import { defineSetupPluginEntry } from "openclaw/plugin-sdk/core";
import { [channelName]Plugin } from "./src/channel.js";

export default defineSetupPluginEntry([channelName]Plugin);
```

This exports the same plugin instance for both runtime and setup phases.

---

## 5. CORE CHANNEL IMPLEMENTATION (src/channel.ts)

### Key Pattern:

All plugins use `createChatChannelPlugin()` to define the channel behavior:

#### IRC Example (Complex with Groups):
- Uses `createScopedChannelConfigAdapter` for multi-account support
- Implements `createChannelDirectoryAdapter` for user/group discovery
- Uses `createResolvedDirectoryEntriesLister` for directory entries
- Defines account resolution with `resolveIrcAccount()`
- Uses `createComputedAccountStatusAdapter` for status
- Implements warning collectors via `composeWarningCollectors()`
- Uses `createScopedDmSecurityResolver` for DM access control

**Key exports**:
```typescript
const ircConfigAdapter = createScopedChannelConfigAdapter<
  ResolvedIrcAccount,
  ResolvedIrcAccount,
  CoreConfig
>({ ... });

const ircPlugin = createChatChannelPlugin({
  id: "irc",
  configAdapter: ircConfigAdapter,
  directoryAdapter: createChannelDirectoryAdapter(...),
  statusAdapter: createComputedAccountStatusAdapter(...),
  listAccountIds: listIrcAccountIds,
  resolveAccount: adaptScopedAccountAccessor(resolveIrcAccount),
  // ... inbound/outbound handlers
});
```

#### Nostr Example (Simpler, Single-Account):
- Uses `createTopLevelChannelConfigAdapter` (not scoped to multiple accounts)
- Implements `createChannelPairingController` for pairing workflow
- Uses `attachChannelToResult` for send results
- Simplified account resolution

**Key handlers**:
```typescript
const nostrPlugin = createChatChannelPlugin({
  id: "nostr",
  configAdapter: nostrConfigAdapter,
  statusAdapter: createComputedAccountStatusAdapter(...),
  async inbound(params) { /* handle inbound DMs */ },
  async outbound(params) { /* send DMs to relays */ },
});
```

---

## 6. CONFIG SCHEMA PATTERNS (src/config-schema.ts)

### IRC Config Schema:
```typescript
// Uses Zod for validation
const IrcGroupSchema = z.object({
  requireMention: z.boolean().optional(),
  tools: ToolPolicySchema,
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  // ... etc
});

export const IrcAccountSchemaBase = z.object({
  name: z.string().optional(),
  enabled: z.boolean().optional(),
  host: z.string().optional(),
  port: z.number().int().min(1).max(65535).optional(),
  tls: z.boolean().optional(),
  nick: z.string().optional(),
  dmPolicy: DmPolicySchema.optional().default("pairing"),
  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  groups: z.record(z.string(), IrcGroupSchema.optional()).optional(),
  channels: z.array(z.string()).optional(),
  // ... many more fields
}).strict();

export const IrcChannelConfigSchema = buildChannelConfigSchema(IrcConfigSchema, {
  uiHints: ircChannelConfigUiHints,
});
```

### Nostr Config Schema (Simpler):
```typescript
export const NostrProfileSchema = z.object({
  name: z.string().max(256).optional(),
  displayName: z.string().max(256).optional(),
  about: z.string().max(2000).optional(),
  picture: safeUrlSchema.optional(),
  // ... etc
});

export const NostrConfigSchema = z.object({
  name: z.string().optional(),
  defaultAccount: z.string().optional(),
  enabled: z.boolean().optional(),
  privateKey: buildSecretInputSchema().optional(),
  relays: z.array(z.string()).optional(),
  dmPolicy: DmPolicySchema.optional(),
  allowFrom: AllowFromListSchema,
  profile: NostrProfileSchema.optional(),
});

export const nostrChannelConfigSchema = buildChannelConfigSchema(NostrConfigSchema);
```

### Key Patterns:
- All use **Zod** for schema validation (`z.object()`, `z.string()`, etc.)
- Import base schemas from `openclaw/plugin-sdk/channel-config-schema`:
  - `DmPolicySchema` (pairing|allowlist|open|disabled)
  - `GroupPolicySchema`
  - `ToolPolicySchema`
  - `MarkdownConfigSchema`
  - `DmConfigSchema`
  - etc.
- Use `.strict()` to prevent additional properties
- Define account-specific schemas that can be multi-account
- Use `buildChannelConfigSchema()` wrapper for JSON schema conversion

