import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
  normalizeOptionalAccountId,
} from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import type { OpenClawConfig } from "../runtime-api.js";
import type { PulseBoardAccountConfig, PulseBoardConfig } from "./types.js";

export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  serverUrl: string;
  apiToken: string;
  username: string;
  config: PulseBoardAccountConfig;
}

function getPulseBoardSection(cfg: OpenClawConfig): PulseBoardConfig | undefined {
  return (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardConfig
    | undefined;
}

function resolveConfiguredDefaultPulseBoardAccountId(
  cfg: OpenClawConfig,
): string | undefined {
  const pbCfg = getPulseBoardSection(cfg);
  return normalizeOptionalAccountId(pbCfg?.defaultAccount);
}

/**
 * List all configured PulseBoard account IDs.
 */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = getPulseBoardSection(cfg);
  const accountMap = pbCfg?.accounts ?? {};
  const explicitIds = Object.keys(accountMap);

  // The top-level section acts as an implicit account when it has credentials
  const hasTopLevel = Boolean(pbCfg?.serverUrl?.trim() && pbCfg?.username?.trim());
  return listCombinedAccountIds({
    configuredAccountIds: explicitIds,
    implicitAccountId: hasTopLevel
      ? (resolveConfiguredDefaultPulseBoardAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

/**
 * Get the default account ID.
 */
export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultPulseBoardAccountId(cfg),
  });
}

/**
 * Resolve a PulseBoard account from config.
 */
export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg),
  );
  const pbCfg = getPulseBoardSection(opts.cfg);

  // Check named accounts first, then fall back to top-level
  const accountCfg =
    (accountId !== DEFAULT_ACCOUNT_ID ? pbCfg?.accounts?.[accountId] : undefined) ?? pbCfg ?? {};

  const serverUrl = accountCfg.serverUrl?.trim() ?? "";
  const username = accountCfg.username?.trim() ?? "";
  const apiToken = accountCfg.apiToken?.trim() ?? "";
  const baseEnabled = accountCfg.enabled !== false;
  const configured = Boolean(serverUrl && username && apiToken);

  return {
    accountId,
    name: accountCfg.name?.trim() || undefined,
    enabled: baseEnabled,
    configured,
    serverUrl,
    apiToken,
    username,
    config: {
      enabled: accountCfg.enabled,
      name: accountCfg.name,
      serverUrl: accountCfg.serverUrl,
      apiToken: accountCfg.apiToken,
      apiTokenFile: accountCfg.apiTokenFile,
      username: accountCfg.username,
      boards: accountCfg.boards,
      dmPolicy: accountCfg.dmPolicy,
      allowFrom: accountCfg.allowFrom,
      groupPolicy: accountCfg.groupPolicy,
      groupAllowFrom: accountCfg.groupAllowFrom,
      groups: accountCfg.groups,
      markdown: accountCfg.markdown,
      textChunkLimit: accountCfg.textChunkLimit,
    },
  };
}

