  const trimmed = target.trim().toLowerCase();
  if (!trimmed) {
    return "";
  }
  // Strip leading @ for user targets
  if (trimmed.startsWith("@")) {
    return trimmed.slice(1);
  }
  return trimmed;
}

/**
 * Returns true when the target looks like a board name (starts with `#`).
 */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Returns true when the input looks like a PulseBoard target id.
 * Accepts `#board` for groups or a bare username for DMs.
 */
export function looksLikePulseBoardTargetId(input: string): boolean {
  const trimmed = input.trim();
  if (!trimmed) {
    return false;
  }
  // Board targets start with #
  if (trimmed.startsWith("#")) {
    return trimmed.length > 1;
  }
  // Usernames: alphanumeric, underscores, hyphens
  return /^@?[\w-]+$/i.test(trimmed);
}

/**
 * Normalize an allowFrom entry for PulseBoard.
 * Returns the lowercase-trimmed username, or null if invalid.
 */
export function normalizePulseBoardAllowEntry(raw: string): string | null {
  const trimmed = String(raw).trim().toLowerCase();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  // Strip leading @ if present
  const cleaned = trimmed.startsWith("@") ? trimmed.slice(1) : trimmed;
  return cleaned || null;
}

